using System.ComponentModel;
using System.Net.Http.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ExternalApiTool
{
    [McpServerTool, Description("Fetches data from an external API for the given resource ID.")]
    public static async Task<string> FetchResource(
        IHttpClientFactory httpClientFactory,
        ILogger<ExternalApiTool> logger,
        [Description("The resource ID to look up")] string resourceId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {ResourceId}", resourceId);

        using var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync($"resources/{resourceId}", cancellationToken);

        if (!response.IsSuccessStatusCode)
        {
            logger.LogWarning("API returned {StatusCode} for {ResourceId}", response.StatusCode, resourceId);
            return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";
        }

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        return content;
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a summarization prompt for the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text content to summarize")] string text,
        [Description("Desired summary style: brief, detailed, or bullet-points")] string style = "brief")
    {
        var systemInstruction = style switch
        {
            "detailed" => "Provide a comprehensive summary that retains key details and nuance.",
            "bullet-points" => "Summarize the content as a concise bulleted list of key points.",
            _ => "Provide a brief, one-paragraph summary capturing the main idea."
        };

        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content { Type = "text", Text = $"{systemInstruction}\n\n---\n\n{text}" }
            }
        ];
    }
}

